void resetToDefault() {
  currentMode = MODE_CLIENT;
  uart2BaudRate = DEFAULT_UART2_BAUD;
  // lowPowerTimeout = DEFAULT_LOWPOWER_TIMEOUT;  // 低功耗超时已禁用
  saveModeToEEPROM();
  saveConfigToEEPROM();
  
  Serial.println("\n? 恢复默认设置！");
  Serial.println("系统将重启...");
  
  // LED闪烁提示
  for (int i = 0; i < 10; i++) {
    setLED(CRGB(255, 0, 0));
    delay(100);
    setLED(CRGB(0, 0, 0));
    delay(100);
  }
  
  delay(500);
  ESP.restart();
}

// ==================== 按键处理 ====================
void handleButton() {
  int buttonState = digitalRead(BUTTON_PIN);
  
  if (buttonState == LOW) {
    if (!buttonPressed) {
      buttonPressed = true;
      buttonPressTime = millis();
    }
  } else {
    if (buttonPressed) {
      unsigned long pressDuration = millis() - buttonPressTime;
      
      if (pressDuration >= LONG_PRESS) {
        Serial.println("检测到长按（" + String(pressDuration) + "ms）- 恢复默认");
        resetToDefault();
      } else if (pressDuration >= 50) {
        Serial.println("检测到短按（" + String(pressDuration) + "ms）- 切换模式");
        switchMode();
      }
      
      buttonPressed = false;
    }
  }
}

