void handleCommand(String command) {
  command.trim();

  if (command.length() == 0) return;

  if (command == "AT+HELP" || command == "AT+?") {
    printHelp();
  } else if (command == "AT+SWITCH") {
    switchMode();
  } else if (command == "AT+RESET") {
    resetToDefault();
  } else if (command == "AT+STATUS") {
    Serial.println("\n系统状态:");
    Serial.println("  模式: " + String(currentMode == MODE_CLIENT ? "客户端" : "服务器"));
    Serial.println("  WiFi: " + String(wifiConnected ? "已连接" : "未连接"));
    Serial.println("  TCP: " + String(tcpConnected ? "已连接" : "未连接"));
    Serial.println("  SD卡: " + String(sdCardReady ? "已就绪" : "未就绪"));
    Serial.println("  日志: " + logFileName + " ("
...[内容已截断]...
) + " 条)");
    Serial.println("  电池: " + String(batteryVoltage) + "V" + (lowBattery ? " (低电量)" : ""));
  } else if (command == "AT+CLIENTS") {
    if (currentMode == MODE_SERVER) {
      int count = getConnectedClientCount();
      Serial.println("\n已连接客户端: " + String(count));
      for (int i = 0; i < MAX_CLIENTS; i++) {
        if (serverClients[i] && serverClients[i].connected()) {
          Serial.println("  客户端 " + String(i) + ": " + serverClients[i].remoteIP().toString());
        }
      }
    } else {
      Serial.println("✗ 此命令仅在服务器模式下可用");
    }
  } else if (command.startsWith("AT+LOGNAME ")) {
    String newName = command.substring(10);
    logFileName = newName;
    saveConfigToEEPROM();
    Serial.println("✓ 日志文件名已设置为: " + logFileName);
  } else if (command.startsWith("AT+BAUD ")) {
    String baudStr = command.substring(8);
    unsigned long newBaud = baudStr.toInt();
    if (newBaud >= 9600 && newBaud <= 921600) {
      uart2BaudRate = newBaud;
      Serial2.begin(uart2BaudRate, SERIAL_8N1, UART2_RX_PIN, UART2_TX_PIN);
      saveConfigToEEPROM();
      Serial.println("✓ UART2波特率已设置为: " + String(uart2BaudRate));
    } else {
      Serial.println("✗ 无效的波特率");

}
  } else if (command == "AT+DEBUG=ON") {
    debugMode = true;
    saveConfigToEEPROM();
    Serial.println("✓ Debug模式已开启");
  } else if (command == "AT+DEBUG=OFF") {
    debugMode = false;
    saveConfigToEEPROM();
    Serial.println("✓ Debug模式已关闭");
  } else if (command == "AT+RESTART") {
    Serial.println("系统将重启...");
    ESP.restart();
  } else if (command == "AT+RAW") {
    // 进入RAW模式（透明透传，不进行命令解析）
    Serial.println("进入RAW模式（输入 'AT+EXIT' 退出）");
    while (true) {
      // 从USB读取并发送到UART2
      if (Serial.available()) {
        String data = Serial.readStringUntil('\n');
        if (data == "AT+EXIT") {
          Serial.println("退出RAW模式");
          break;
        }
        Serial2.println(data);
      }

      // 从UART2读取并发送到USB
      if (Serial2.available()) {
        String data = Serial2.readStringUntil('\n');
        Serial.println("[UART2] " + data);
      }

      delay(10);
    }
  } else if (command == "AT+POWER=ON") {
    powerOn();
  } else if (command == "AT+POWER=OFF") {
    powerOff();
  } else if (command == "AT+POWER=TRIGGER") {
    triggerShutdown();
  } else if (command == "AT+RESET=CPU") {
    resetCPU();
  } else {
    // 未知命令，发送到UART2
    Serial2.println(command);
    Serial.println("[发送] " + command);
  }
}

